def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 2, -2):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 7) / (a * b * 1.1 + 2)
                    priority += val * np.sin(ratio * b / (a + 2)) * np.exp(-b / (a + 3))
            if ratio % 2 < 1:
                priority += (np.exp(ratio - 7) * np.cos(ratio * 1.4)) ** 2
            else:
                priority += (np.log(ratio + 0.1) * np.sin(ratio * 0.9)) ** 1.7
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    temp = ((ratio - p) ** 4) * np.cos(ratio * p * 0.9) / (q + 0.3)
                    priority += np.tanh(temp) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            priority += np.sin(i * ratio) * 0.8
        elif 2.5 <= ratio <= 5:
            s = 0
            for r in range(2, 15):
                s += ((ratio - 2.5) ** r) / (r * 2.1) * np.sin(r * ratio * 0.8)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            for m in range(1, 6):
                priority += np.cos(m * ratio * i * 0.7) * ((ratio - 2.5) ** m) / (m + 1)
        elif 1.0 <= ratio < 2.5:
            s1 = 0
            s2 = 0
            for n in range(1, 12):
                s1 += ((2.5 - ratio) ** n) / (n ** 2 + 1)
                s2 += ((ratio - 1.0) ** n) / (n * 1.5) * np.sin(n * ratio)
            if bin_cap < item * 0.95:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
                priority = s1 + s2 + penalty + np.exp(-2 / (ratio + 0.1))
            else:
                penalty = np.cos(25 * ratio) * 3
                priority = s1 + s2 + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1.0) ** m) / (m + 2)
        elif 0.5 <= ratio < 1.0:
            s = 0
            for k in range(1, 20):
                s += ((1.0 - ratio) ** k) / (k * 3.5) * np.sin(k * ratio * 1.5)
            priority = s / (np.sqrt(bin_cap + 2) + 1)
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 3) + 3)
            for j in range(1, 8):
                priority += ((1.0 - ratio) ** j) * np.cos(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 15):
                s += ((0.5 - ratio) ** l) / (l * 4.5) * np.cos(l * ratio * 2.2)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.7) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6
            for v in range(1, 5):
                priority += np.sin(ratio * v * i) * ((ratio - 0.7) ** v) / v
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
            for w in range(1, 5):
                priority -= np.cos(ratio * w * i) * ((bin_cap - item * 3) / item) / (w + 1)
        for idx in range(1, 5):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
